 1	import React, { FC, ReactNode } from 'react';
 2	
 3	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 4	
 5	type HidableTooltipProps = {
 6	  children: ReactNode;
 7	  content: ReactNode;
 8	  hidden: boolean;
 9	  position?: TooltipPosition;
10	};
11	
12	const HidableTooltip: FC<HidableTooltipProps> = ({
13	  children,
14	  content,
15	  hidden,
16	  position = TooltipPosition.right,
17	}) => {
18	  return hidden ? (
19	    <>{children}</>
20	  ) : (
21	    <Tooltip content={content} position={position}>
22	      <>{children}</>
23	    </Tooltip>
24	  );
25	};
26	
27	export default HidableTooltip;

